+bool IsValidPhpNamespace(absl::string_view name, bool allow_root_namespace) {
+  if (name.empty()) {
+    return true;
+  }
+  if (allow_root_namespace && name == "\\") {
+    return true;
+  }
+
+  bool segment_start = true;
+  for (char c : name) {
+    if (c == '\\') {
+      if (segment_start) {
